    let result: u32 = factorial(10_u32)
    var buf: [12]u8 = [0_u8; 12]
    let formatted: Maybe<Span<u8>> = std.fmt.u32(buf, result)
    if formatted.has {
        check world.out.write(formatted.value)
        check world.out.write("\n")
    }
}

fn factorial(n: u32) -> u32 {
    var i: u32 = 2
    var total: u32 = 1
    while i <= n {
        total = total * i
        i = i + 1
    }
    return total
}
